const notes = $json.meeting_notes || $json.body?.meeting_notes || '';
const title = $json.meeting_title || $json.body?.meeting_title || 'İsimsiz Toplantı';
const date  = $json.meeting_date  || $json.body?.meeting_date  || new Date().toISOString().split('T')[0];
const action = $json.action || $json.body?.action || 'analyze';
const action_items = $json.action_items || $json.body?.action_items || [];

const cleanNotes = notes
  .substring(0, 4000)
  .trim()
  .replace(/\n/g, ' ')      // newlines → space
  .replace(/\r/g, ' ')      // carriage returns → space
  .replace(/\t/g, ' ')      // tabs → space
  .replace(/\\/g, '\\\\')   // backslashes → escaped
  .replace(/"/g, '\\"');    // quotes → escaped

const defaultDeadline = new Date();
defaultDeadline.setDate(defaultDeadline.getDate() + 7);
const defaultDeadlineStr = defaultDeadline.toISOString().split('T')[0];

return [{
  json: {
    meeting_title:    title,
    meeting_notes:    cleanNotes,
    meeting_date:     date,
    default_deadline: defaultDeadlineStr,
    processed_at:     new Date().toISOString(),
    action:           action,        // YENİ
    action_items:     action_items,  // YENİ
  }
}];

// HTTP Request çıktısından Gemini metnini al
const raw = $input.first().json.candidates[0].content.parts[0].text;

// Markdown temizle
let cleaned = raw
  .replace(/```json/gi, '')
  .replace(/```/g, '')
  .trim();

// İlk { ile son } arasını al
const firstBrace = cleaned.indexOf('{');
const lastBrace = cleaned.lastIndexOf('}');
cleaned = cleaned.substring(firstBrace, lastBrace + 1);

// Parse et
const parsed = JSON.parse(cleaned);

// action_items içindeki her item'a meeting_title ve follow_up_date ekle
const meetingTitle = parsed.meeting_title || 'Bilinmeyen';
const followUpDate = parsed.follow_up_date || '';
const meetingDate = parsed.meeting_date || '';

// Her action_item'ı ayrı bir output item olarak döndür
const items = parsed.action_items.map(item => ({
  json: {
    person:         item.person    || 'Belirsiz',
    task:           item.task      || '',
    deadline:       item.deadline  || '',
    priority:       item.priority  || 'Orta',
    notes:          item.notes     || null,
    meeting_title:  meetingTitle,
    follow_up_date: followUpDate,
    meeting_date:   meetingDate
  }
}));

return items;

const items = $input.all();

const results = items.map(inputItem => {
  const item = inputItem.json;

  const task =     item.task        || item.gorev    || 'Görev belirtilmedi';
  const person =   item.person      || item.sorumlu  || 'Ekip Üyesi';
  const deadline = item.deadline    || 'Belirtilmedi';
  const priority = item.priority    || item.oncelik  || 'Orta';
  const meeting =  item.meeting_title || item.toplanti_adi || 'Toplantı';
  const email =    item.person_email || item.email   || 'takim11hackathon@gmail.com';

  let tone = '';
  if (priority === 'Yüksek') {
    tone = 'Bu görev KRİTİK öneme sahiptir ve en kısa sürede tamamlanmalıdır.';
  } else if (priority === 'Orta') {
    tone = 'Bu görev planlı şekilde ilerletilmelidir.';
  } else {
    tone = 'Bu görev uygun zaman planlamasıyla tamamlanabilir.';
  }

  const subject = `[${priority}] Görev Atama: ${task}`;
  const body = `Merhaba ${person},

"${meeting}" toplantısı kapsamında sana yeni bir görev atanmıştır.

Görev: ${task}
Öncelik: ${priority}
Son Tarih: ${deadline}

Not: ${tone}

Lütfen belirtilen tarihe kadar tamamlamanı rica ederiz.

Teşekkürler,
MeetMind Sistemi`.trim();

  return {
    json: {
      email_subject:   subject,
      email_body:      body,
      recipient_email: email,
      recipient_name:  person,
      task,
      deadline,
      priority,
      meeting_title:   meeting,
      follow_up_date:  item.follow_up_date || '',
      sorumlu:         person,
      gorev:           task,
      toplanti_adi:    meeting
    }
  };
});

return results;

const items = $input.all();
const now = new Date();
const pad = n => String(n).padStart(2, '0');
const today = `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}`;

const results = items.map(inputItem => {
  const item = inputItem.json;

  const followUpDate = item.follow_up_date || (() => {
    const d = new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000);
    return `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`;
  })();

  const id = `MM-${now.getFullYear()}${pad(now.getMonth()+1)}${pad(now.getDate())}-${Math.floor(Math.random()*9000+1000)}`;

  return {
    json: {
      id:             id,
      tarih:          today,
      toplanti_adi:   item.meeting_title  || 'Bilinmeyen',
      sorumlu:        item.person         || 'Belirsiz',
      gorev:          item.task           || '',
      deadline:       item.deadline       || today,
      oncelik:        item.priority       || 'Orta',
      durum:          'Bekliyor',
      notlar:         item.notes          || '',
      follow_up_date: followUpDate,
      meeting_title:  item.meeting_title  || 'Bilinmeyen',
      person:         item.person         || 'Belirsiz',
      task:           item.task           || '',
      priority:       item.priority       || 'Orta',
      deadline_raw:   item.deadline       || today
    }
  };
});

return results;

// Hem Türkçe hem İngilizce alan isimlerini dene
const priority = $json.priority || $json["Öncelik"] || $json.oncelik || 'Orta';
const deadline = $json["Deadline"] || $json.deadline || $json.deadline_raw || '';
const sorumlu = $json["Sorumlu"] || $json.sorumlu || $json.person || 'Belirsiz';
const gorev = $json["Görev"] || $json.gorev || $json.task || '';
const toplanti = $json["Toplantı Adı"] || $json.toplanti_adi || $json.meeting_title || '';
const followUp = $json["follow_up_date"] || $json.follow_up_date || deadline;

const colorMap = {
  'Yüksek': '11',
  'Orta':   '5',
  'Düşük':  '2',
};

return [{ 
  json: {
    ...($json),
    calendar_color:  colorMap[priority] || '1',
    priority:        priority,
    deadline:        deadline,
    sorumlu:         sorumlu,
    gorev:           gorev,
    toplanti_adi:    toplanti,
    follow_up_date:  followUp
  }
}];

const items = $input.all();

// Sadece ilk item'dan follow_up_date al
// Çünkü tüm itemlar aynı toplantıdan geliyor
const item = items[0].json;

const followUp = item.follow_up_date || '';

if (!followUp) {
  return [{
    json: {
      hata: 'follow_up_date bulunamadı',
      gelen_alanlar: Object.keys(item)
    }
  }];
}

return [{
  json: {
    follow_up_date: followUp,
    toplanti_adi: item.toplanti_adi || item.meeting_title || 'Takip Toplantısı',
    sorumlu: item.sorumlu || item.person || 'Ekip'
  }
}];

const notes = $json.meeting_notes;
const meetingDate = $json.meeting_date;
const meetingTitle = $json.meeting_title;

const body = {
  contents: [{
    role: "user",
    parts: [{
      text: `Sen bir toplantı asistanısın. Aşağıdaki toplantı notunu analiz et.
SADECE JSON döndür. Markdown kullanma. Açıklama yazma.

TOPLANTI NOTU:
${notes}

Şu formatta yanıt ver:
{
  "meeting_title": "string",
  "meeting_date": "YYYY-MM-DD",
  "follow_up_date": "YYYY-MM-DD",
  "action_items": [
    {
      "person": "Ad Soyad",
      "task": "Görev",
      "deadline": "YYYY-MM-DD",
      "priority": "Yüksek",
      "notes": null
    }
  ]
}

KURALLAR:
- meeting_title olarak "${meetingTitle}" kullan, değiştirme.
- Bugünün tarihi: ${meetingDate}. Tüm deadline'lar bu tarihten sonra olmalı, geçmiş tarih kullanma.
- deadline yoksa bugundan 7 gun sonrasini kullan
- priority sadece: Yuksek, Orta, Dusuk
- follow_up_date: meeting_date + 7 gun
- Kisi adi belirsizse: Belirsiz yaz`
    }]
  }],
  generationConfig: {
    temperature: 0.1,
    maxOutputTokens: 8192
  }
};

return [{
  json: {
    ...$json,
    gemini_body: JSON.stringify(body)
  }
}];

const items = $json.action_items || [];
const meetingTitle = $json.meeting_title || 'İsimsiz Toplantı';
const meetingDate = $json.meeting_date || new Date().toISOString().split('T')[0];

return items.map(item => ({
  json: {
    meeting_title: meetingTitle,
    meeting_date:  meetingDate,
    person:        item.person,
    task:          item.task,
    deadline:      item.deadline,
    priority:      item.priority,
    notes:         item.notes || null,
    status:        'Bekliyor',
  }
}));

const items = $input.all().map(item => ({
  person:   item.json.person   || item.json.sorumlu,
  task:     item.json.task     || item.json.gorev,
  deadline: item.json.deadline || item.json.deadline_raw,
  priority: item.json.priority || item.json.oncelik,
  notes:    item.json.notlar   || null,
}));

const first = $input.first().json;

return [{
  json: {
    meeting_title: first.meeting_title || first.toplanti_adi,
    meeting_date:  first.tarih,
    action_items:  items,
  }
}];
